PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX geof: <http://www.opengis.net/def/function/geosparql/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
SELECT ?municipality ?municipalityLabel ( AVG( ?lat ) AS ?avgLat ) ( AVG( ?lon ) AS ?avgLon ) ( AVG( ?pop ) AS ?avgPop ) WHERE {
  ?municipality wdt:P31 / wdt:P279 * wd:Q667509 .
  FILTER NOT EXISTS {
    ?municipality wdt:P31 wd:Q19347965
  }
  FILTER NOT EXISTS {
    ?municipality p:P576 ?diss
  }
  OPTIONAL {
    ?municipality wdt:P625 ?coord .
    BIND( geof:latitude ( ?coord ) AS ?lat ) BIND( geof:longitude ( ?coord ) AS ?lon )
  }
  OPTIONAL {
    ?municipality p:P1082 ?popStmt .
    ?popStmt ps:P1082 ?pop .
  }
  ?municipality rdfs:label ?municipalityLabel .
  FILTER ( LANG( ?municipalityLabel ) = "de" )
}
GROUP BY ?municipality ?municipalityLabel
ORDER BY ?municipalityLabel

